INSERT INTO `faqs` (`id`, `question`, `answer`, `created_at`, `updated_at`) VALUES
(2, 'ডেলিভারী চার্জ কত ?', 'ডেলিভারী চার্জ মাত্র ১০, ২০ টাকা। যে সকল  এলাকায় ডেলিভারী চার্জ  ১০ টাকা ( সোনাডাঙ্গা ১ম, ২য়, ৩য় ফেজ আবাসিক এলাকা, গোবরচাকা, শিববাড়ী, নিউমার্কেট )', '2022-08-16 16:21:48', '2024-08-03 09:45:34'),
(3, 'আপনাদের ডেলিভারী খুলনার কোন কোন এলাকাতে করেন ?', 'আমরা খুলনা শহরের সকল এলাকাতে ডেলিভারী করে থাকি।', '2022-08-16 16:24:04', '2022-08-16 16:24:04'),
(4, 'যোগাযোগ এর উপায় কি ?', 'আপনি ফোন এ যোগাযোগ করতে 01322-882568 নাম্বারে কল করুন সকাল ৯ টা থেকে রাত ৯ টা পর্যন্ত এবং মেইল করুন jonopriyobazar@gmail.com ।', '2022-08-16 16:53:46', '2024-08-03 03:47:49'),
(5, 'বাজার আসতে কত সময় লাগতে পারে ?', 'আমরা বর্তমানে ময়লাপোতা ও গল্লামারী থেকে বয়রা পর্যন্ত এর মধ্যের এলাকা গুলোতে ১ ঘন্টায় ডেলিভারী করি। এবং বয়রা এলাকার পর থেকে গীলাতলা ক্যান্টেনমেন্ট পর্যন্ত এর মধ্যের এলাকা গুলোতে ৬ ঘন্টার মধ্যে ডেলিভারী করি।', '2022-08-16 16:59:43', '2026-01-07 19:27:28'),
(6, 'ফোনে কি অর্ডার করা যায় ?', 'হ্যা যায়, ফোনে অর্ডার করতে আপনি কল করুন 01322-882568 নাম্বারে সকাল ৯ টা থেকে রাত ৯ টা পর্যন্ত। অথবা হোয়াটসঅ্যাপ এ আপনার বাজার লিস্ট লিখে কিংবা বাজার লিস্টের ছবি তুলে দিতে পারেন 01322-882568 এই হোয়াটসঅ্যাপ নাম্বারে।', '2022-08-16 17:08:54', '2024-08-03 09:58:58'),
(7, 'মূল্য পরিশোধ এর উপায় কি ?', 'আপনি ডেলিভারীর সময় পণ্য যাচাই করে মূল্য পরিশোধ করতে পারবেন। এছাড়া বিকাশ, নগদ, রকেট, উপায়  এবং ব্যাংকের ভিসা, মাস্টারকার্ড ও আমেরিকান এক্সপ্রেস কার্ড এর  মাধ্যমে মূল্য পরিশোধ করতে পারবেন ঘরে বসে পণ্য হাতে পেয়ে।', '2022-08-16 17:11:52', '2024-08-03 10:15:14'),
(8, 'বাজারে কিছু সমস্যা দেখা দিয়েছে, কি করতে পারি ?', 'যে কোন ধরনের সমস্যার জন্য কল করুন 01322-882568 নাম্বারে কল করুন সকাল ৯ টা থেকে রাত ৯ টা পর্যন্ত। আমাদের প্রতিনিধিগন সকল সমস্যার সমাধানে সর্বদা নিয়োজিত আছে।', '2022-08-16 17:13:44', '2024-08-03 10:16:34'),
(9, 'এলাকার বাজার অথবা দোকান বাদ দিয়ে আপনাদের থেকে নিব কেন ?', 'সময় বাচান। এছাড়া শহরের অন্যান্য সুপার স্টোর গুলোর চেয়ে আমাদের সাইটে পণ্যর দাম কম/সমান এবং আপনার বাসার পাশের মুদি দোকানের চেয়ে বেশি পণ্য আমাদের কাছ থেকে পাবেন। তাহলে কেন কষ্ট করে আর বাজারে যাওয়া।', '2022-08-16 17:14:29', '2022-08-16 17:14:29'),
(10, 'দ্রব্যমূল্য কত বেশি ?', 'আমাদের পণ্যের দর বাজারে প্রচলিত মূল্যের কম অথবা সমান কিন্তুু কোনক্রমেই বেশি নয় এবং কোন ধরনের অতিরিক্ত কর মুক্ত।', '2022-08-16 17:15:04', '2022-08-16 17:30:56'),
(11, 'আপনারা কিভাবে ডেলিভারী করে থাকেন ?', 'আমাদের নিজস্ব বাহন রয়েছে এবং আমরা সরবারহ ব্যবস্থাপনায় স্বয়ংসম্পূন। তবে আমাদের ডেলিভারী প্রতিনিধিরা যে কোন উপায়ে আপনার বাজার আপনার নিকট পৌঁছে দেওয়ার প্রশিক্ষন প্রাপ্ত।', '2022-08-16 17:15:36', '2022-08-16 17:15:36'),
(12, 'পণ্য ফেরত এর কোন সুযোগ আছে কি ?', 'আমরা ১০ দিনের মাঝে পণ্য ফেরত নেই যদি তা নষ্ট অথবা খোলা না হয়ে থাকে। তবে মাছ -মাংস, শাক-সবজি, ফল, রুটি, খেলনা-সো পিছ , পোশাক এবং পচনশীল পণ্যের ক্ষেতে পণ্য দেখে গ্রহনের আগ মুহূত পর্যন্ত  রিটান পলিসি প্রযোজ্য।', '2022-08-16 17:17:27', '2022-08-16 17:17:27'),
(13, 'পণ্যের গুনগত মান কেমন ?', 'আমরা আমাদের সকল পণ্য সরাসরি উৎপাদনকারীদের  থেকে সংগ্রহ করা হয় অথবা অত্যন্ত বিশ্বস্ত জায়গা থেকে সংগ্রহীত হয়। তবু ও যদি আমরা গ্রাহকদের সন্তষ্ট করতে ব্যর্থ হই তাহলে পণ্য ১০ দিনের মাঝে অব্যশই ফেরতযোগ্য।', '2022-08-16 17:19:19', '2022-08-16 17:19:19'),
(14, 'হরতাল অবরোধে কি ডেলিভারী হয় ?', 'অব্যশই হয়, আমাদের লক্ষ্যই হলো বাজার সম্পর্কিত সকল ঝামেলা দূর করে দেওয়া। তবে বড় কোন ঝামেলা হলে ডেলিভারী সময়ে কিছুটা তারতম্য হতে পারে।', '2022-08-16 17:19:47', '2022-08-16 17:19:47'),
(15, 'বাকিতে কি পণ্য ক্রয় করা যাবে ?', 'হ্যা যাবে, আপনার ক্রয়ের উপর ভিত্তি করে এই সুবিধা দেওয়া হবে।', '2022-08-16 17:20:17', '2022-08-16 17:20:17'),
(16, 'বিকাশে অথবা নগদে লেনদেন করলে টাকা পাব কিংবা দিব কি করে ?', 'আপনি ফোন করে আপনার (ক্যাশ ইন অথবা ক্যাশ আউট) লেনদেন এর কোনটা করতে চাচ্ছেন তা জানালে, আমাদের একজন প্রতিনিধি আপনার নিকট পৌঁছে লেনদেন সম্পূন করবে। এই সার্ভিস এ ডেলিভারী চার্জ মাত্র ১০, ২০ টাকা। যে সকল এলাকায় ডেলিভারী চার্জ ১০ টাকা ( সোনাডাঙ্গা ১ম, ২য়, ৩য় ফেজ আবাসিক এলাকা, গোবরচাকা, শিববাড়ী, নিউমার্কেট ) প্রযোজ্য।', '2022-08-16 17:21:14', '2024-08-03 10:20:26'),
(17, 'রিওয়ার্ড কি করে পাব ?', 'জনপ্রিয়বাজার এর ওয়েব সাইট থেকে পণ্য ক্রয় করলে আপনি যে পয়েন্ট গুলো পাবেন। সেই পয়েন্ট ব্যবহার করে আপনি আকর্ষনীয় গিফট সংগ্রহ করতে পারবেন।', '2022-08-16 17:21:52', '2022-08-16 17:21:52'),
(18, 'ডেলিভারী প্রতিনিধিকে কি কোন বকশিশ দিতে হবে ?', 'বকশিশ দেওয়া আবশ্যক নয়।', '2022-08-16 17:27:09', '2022-08-16 17:27:09'),
(19, 'সাইট টি কিভাবে ব্যবহার করে বা কিভাবে অর্ডার করবো ?', 'প্রথমে আমাদের সাইট www.jonopriyobazar.com যাবেন, সেখানে আপনি ক্যাটাগরি ঘুরে আপনার প্রয়োজনীয় পণ্য কিনতে পারবেন অথবা Search বার এ আপনার প্রয়োজনীয় পণ্যর নাম লিখলে পণ্যটি আপনার সামনে আসবে এবং আপনি আপনার শপিং ব্যাগে এড করতে পারবেন। আপনার প্রয়োজনীয় সকল পণ্য ব্যাগে নেওয়া শেষ হলে তারপর চেক আউটে আপনার তথ্য দিয়ে অর্ডার নিশ্চিত করুন। এরপর আমাদের একজন প্রতিনিধি আপনাকে ফোন করে অর্ডার এর সত্যতা যাচাই করবে। এবং আমাদের ডেলিভারী প্রতিনিধি বাজার টি আপনার বাসায় পৌছে দিবে।', '2022-08-16 17:28:52', '2022-08-17 23:34:32'),
(20, 'এখানে কি কোন রেজিষ্টেশন করতে হবে ?', 'রেজিষ্টেশন করা আবশ্যক। আমাদের কাস্টমারদের বিশেষ কিছু সুবিধার জন্য সর্বদা রেজিষ্টেশন করতে বলি। এতে কাস্টমার যেমন সহজে বাজার করতে পারবে তেমনি আমাদের ও সঠিকতা যাচাইয়ে সুবিধা হয়। এছাড়া ও কাস্টমারের লেনদেন ও ক্রয় ডাটা সংগ্রহ থাকায় পরবর্তিতে তার ক্রয়ের উপর ভিত্তি করে বিভিন্ন সুবিধা দেওয়া হয়।', '2022-08-17 23:37:36', '2022-08-17 23:37:36'),
(21, 'যদি আরো প্রশ্ন থাকে', 'আপনার আরো কোন প্রশ্ন কিংবা পরামর্শ থাকলে আমাদের 01322-882568 নাম্বারে কল করুন কিংবা মেইল করুন jonopriyobazar@gmail.com এ.', '2022-08-17 23:39:34', '2024-08-03 10:22:43'),
(22, 'বিদ্যুতের প্রিপেইড মিটার রিচার্জ ও পোস্টপেইড মিটার এর বিদ্যুৎ বিল দেওয়া যায় ?', 'উত্তরঃ হ্যা যায়, আপনি ফোন করে অথবা হোয়াটসঅ্যাপ এ প্রিপেইড মিটার রিচার্জ ও পোস্টপেইড মিটার এর বিদ্যুৎ বিল দেওয়ার বিষয় জানালে, আমাদের একজন প্রতিনিধি আপনার নিকট পৌঁছে লেনদেন সম্পূন করবে। মিটার রির্চাজ চার্জ প্রতি হাজারে ১০ টাকা। এই সার্ভিস এ ডেলিভারী চার্জ মাত্র ১০, ২০ টাকা। যে সকল এলাকায় ডেলিভারী চার্জ ১০ টাকা ( সোনাডাঙ্গা ১ম, ২য়, ৩য় ফেজ আবাসিক এলাকা, গোবরচাকা, শিববাড়ী, নিউমার্কেট ) প্রযোজ্য।', '2024-08-03 10:33:42', '2024-08-03 10:40:04');
