(195, 'Horlicks Chocolate Flavour Jar', 'horlicks-chocolate-flavour-jar', '500 gm', 540, 550, 0, 1, 2, '1767856941-image-Horlicks Chocolate Flavour Jar-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;segoe ui&quot;, Helvetica, &quot;droid sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Filled with a wide range of vitamins and minerals including as Calcium, Iron, Zinc, Phosphorous, Vitamins A, C, E, D, B1, B2, B6, B12 - Horlicks is a nourishing beverage that helps support your child’s growth. Produced from a mix of malted barley, wheat and milk, this unrivaled tasty recipe has been providing nutrition to people for many years. Horlicks helps to make kids Taller, Stronger and Sharper! Now available in delicious Chocolate Flavor!</span><br></p>', 1, 3, '2021-07-12 23:55:12', '2026-01-08 18:22:21'),
(196, 'Junior Horlicks Health And Nutrition Drink BIB', 'junior-horlicks-health-and-nutrition-drink-bib', '500 gm', 430, 430, 0, NULL, 2, '1626120081-image-Junior Horlicks Health And Nutrition Drink BIB 500 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;segoe ui&quot;, Helvetica, &quot;droid sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Junior Horlicks provides nutrition for the junior. It has DHA which, along with other vital nutrients, helps in junior’s brain development and function. With 20 Vital Micronutrients, Junior Horlicks aids in optimal height, weight gain and brain development and function. Give your champ Junior Horlicks today for the “Right Start for Right Growth”.</span><br></p>', 0, 3, '2021-07-13 00:01:21', '2026-01-08 18:14:10'),
