(200, 'Ovaltine Power 10 Chocolate Drink Jar', 'ovaltine-power-10-chocolate-drink-jar', '400 gm', 700, 710, 0, 1, 5, '1626121731-image-Ovaltine Power 10 Chocolate Drink Jar 400 gm-compressed.jpg', NULL, 0, 3, '2021-07-13 00:28:51', '2026-01-02 20:19:19'),
(201, 'Horlicks Growth Plus Health And Nutrition Drink Vanilla Jar', 'horlicks-growth-plus-health-and-nutrition-drink-vanilla-jar', '400 gm', 830, 840, 1, 1, 5, '1626121995-image-Horlicks Growth Plus Health And Nutrition Drink Vanilla Jar 400 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;segoe ui&quot;, Helvetica, &quot;droid sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Horlicks Growth Plus is clinically proven to increase growth in children in 6 months. It is specially formulated with high quality whey protein to help children who had fallen behind the average height and weight for their age. Enjoyed twice daily mixed with hot or cold water or milk, it contains high quality whey protein to improve weight gain, and essential amino acids to naturally activate growth for strong, healthy children. It is designed to naturally enhance growth without causing obesity in children. It also contains important nutrients.</span><br></p>', 0, 3, '2021-07-13 00:33:15', '2026-01-02 20:19:13'),
(202, 'Complan Creamy Classic Plain', 'complan-creamy-classic-plain', '350 gm', 355, 360, 0, 1, 5, '1626122225-image-Complan Creamy Classic Plain 350 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;segoe ui&quot;, Helvetica, &quot;droid sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Complan Plan has 2X milk protein which helps in children\'s growth, development and maintenance body. Complan provide all 9 essential Amino Acids which are indispensable Amino Acids and essential part of dietary protein requirement of human body. Protein helps in repair and replacement of body issues and muscle formation.</span><br></p>', 0, 3, '2021-07-13 00:37:05', '2026-01-02 20:19:05'),
(203, 'Complan Chocolate Jar', 'complan-chocolate-jar', '200 gm', 245, 250, 0, 2, 2, '1626122448-image-Complan Chocolate Jar 200 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;segoe ui&quot;, Helvetica, &quot;droid sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Complan Chocolate is a nourishing drink that can be made up with either milk or water. Sip it warm; enjoy it chilled; add a little to your favourite recipes.</span><br></p>', 0, 3, '2021-07-13 00:40:48', '2026-01-02 20:18:56'),
(204, 'Meril Baby Shampoo', 'meril-baby-shampoo-110-ml', '110 ml', 210, 225, 1, 6, 5, '1768371123-image-Meril Baby Shampoo 110 ml-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Meril Baby Shampoo 110 ml is specially formulated to gently cleanse your baby\'s delicate hair and scalp with a mild, tear-free formula. Enriched with natural ingredients, it nourishes and hydrates, ensuring softness and shine. Ideal for sensitive skin, this shampoo is free from harsh chemicals and prevents eye irritation, making bath time enjoyable. It rinses off easily without residue. Simply apply to wet hair, lather, and rinse thoroughly for clean, healthy hair every day.</span></p>', 1, 3, '2021-07-13 11:50:09', '2026-01-14 17:12:03'),
(205, 'Parachute Just For Baby Wash', 'parachute-just-for-baby-washs-200-ml', '200 ml', 225, 235, 1, 4, 5, '1626162891-image-Parachute Just For Baby Wash 200 ml-compressed.jpg', '<p data-reactid=\".1ryw3pnq8ly.6.2.0.0.0.0.2.5.1.0:$p15703.4.0.1.0.1.4.$line-0\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;segoe ui&quot;, Helvetica, &quot;droid sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Parachute Just for Baby - Baby Wash</p><p data-reactid=\".1ryw3pnq8ly.6.2.0.0.0.0.2.5.1.0:$p15703.4.0.1.0.1.4.$line-1\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;segoe ui&quot;, Helvetica, &quot;droid sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Just for Baby Body &amp; Hair wash gently cleanses your baby’s hair and body, leaving it nicely scented. No tears formula lets your baby enjoy the bath while maintaining natural softness of Baby’s skin.</p><p data-reactid=\".1ryw3pnq8ly.6.2.0.0.0.0.2.5.1.0:$p15703.4.0.1.0.1.4.$line-2\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;segoe ui&quot;, Helvetica, &quot;droid sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\"></p><p data-reactid=\".1ryw3pnq8ly.6.2.0.0.0.0.2.5.1.0:$p15703.4.0.1.0.1.4.$line-3\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;segoe ui&quot;, Helvetica, &quot;droid sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">It has been tested for allergy &amp; formulated with 100% safe ingredien</p>', 0, 3, '2021-07-13 11:54:51', '2026-01-02 20:50:10'),
(206, 'Meril Baby Mild Honey Soap', 'meril-baby-mild-honey-soap', '75 gm', 90, 95, 1, 5, 5, '1768374406-image-Meril Baby Mild Honey Soap 75 gm-compressed.jpg', '<p data-reactid=\".1ryw3pnq8ly.6.2.0.0.0.0.2.5.1.0:$p10253.4.0.1.0.1.4.$line-0\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;segoe ui&quot;, Helvetica, &quot;droid sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\"><span style=\"color: rgb(67, 69, 70); font-family: Poppins, sans-serif;\">Meril Baby Soap is specially designed to meet the needs of your baby\'s delicate and thin skin. Unlike harsh adult soaps, this specialized soap is formulated to provide gentle care during bath time. Infused with lotion and honey, Meril Baby Soap offers a moisturizing experience for your little one\'s skin. It is 5 times milder than adult soap, ensuring a gentle cleanse without causing dryness or irritation. The presence of honey not only adds moisture but also helps to keep the skin soft, supple, and healthy. With Meril Baby Soap, you can provide the best care and growth for your baby\'s skin.</span></p>', 1, 3, '2021-07-13 11:58:01', '2026-01-14 18:06:46'),
(207, 'Parachute Just For Baby Powder', 'parachute-just-for-baby-powders-200-gm', '200 gm', 190, 200, 1, 5, 5, '1626163279-image-Parachute Just For Baby Powder 200 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;segoe ui&quot;, Helvetica, &quot;droid sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Just for Baby Powder with goodness of Almond Milk &amp; Neemcreates a barrier that locks moisture for 24 hours &amp; protects your baby’s beautiful skin from dryness. This rich nourishing lotion enriched with vitamin E gets easily absorbed in your baby’s skin &amp; keeps it smooth and soft naturally.</span><br></p>', 0, 3, '2021-07-13 12:01:19', '2026-01-02 20:49:59'),
