(493, 'Jira (Cumin Seed)', 'jira-cumin-seed-', '100 gm', 65, 70, 1, 7, 2, '1628110906-image-Cumin Seed (Jira) 100 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Cumin (Jira) is a spice widely used in cooking for its distinctive warm, earthy, and slightly peppery flavor. It is a popular ingredient in various cuisines, including Indian, Middle Eastern, and Mexican. Cumin is known for its aromatic qualities and is often used in spice blends, curries, and stews.</span></p>', 1, 3, '2021-08-05 01:01:46', '2026-02-01 19:38:10'),
(494, 'Jira (Cumin Seed)', 'jira-cumin-seed-50-gm', '50 gm', 33, 35, 0, 5, 0, '1628111069-image-Jira (Cumin Seed) 50 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Cumin (Jira) is a spice widely used in cooking for its distinctive warm, earthy, and slightly peppery flavor. It is a popular ingredient in various cuisines, including Indian, Middle Eastern, and Mexican. Cumin is known for its aromatic qualities and is often used in spice blends, curries, and stews.</span></p>', 1, 3, '2021-08-05 01:04:29', '2026-02-01 19:37:59'),
(495, 'Jira (Cumin Seed)', 'jira-cumin-seed-250-gm', '250 gm', 160, 175, 1, 8, 5, '1628111245-image-Jira (Cumin Seed) 250 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Cumin (Jira) is a spice widely used in cooking for its distinctive warm, earthy, and slightly peppery flavor. It is a popular ingredient in various cuisines, including Indian, Middle Eastern, and Mexican. Cumin is known for its aromatic qualities and is often used in spice blends, curries, and stews.</span></p>', 1, 3, '2021-08-05 01:07:25', '2026-02-01 19:37:48'),
(496, 'Daruchini (Cinnamon)', 'daruchini-cinnamon-', '50 gm', 30, 35, 1, 14, 5, '1628111425-image-Daruchini (Cinnamon) 50 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Cinnamon is used mainly as an aromatic condiment and flavoring additive in a wide variety of cuisines, sweet and savory dishes, breakfast cereals, snack foods, tea, and traditional foods.</span></p>', 1, 3, '2021-08-05 01:10:25', '2026-02-01 19:35:46'),
(497, 'Elachi (Cardamom)', 'elachi-cardamom-', '10 gm', 60, 65, 1, 7, 2, '1628111606-image-Elachi (Cardamom) 10 gm-compressed.jpg', '<p data-reactid=\".ro2titl27u.$16206.0.1.0.1.4.$line-2\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Elach, Cardamom (Elachi) is a spice with an intense, slightly sweet flavor that some people compare to mint. Its antioxidant and diuretic properties may lower blood pressure. The compounds in cardamom may help fight cancer cells. Each is rich in compounds that may fight inflammation. Cardamom has been used for thousands of years to help with digestion. The use of cardamom to treat bad breath and improve oral health is an ancient remedy.</p><p data-reactid=\".ro2titl27u.$16206.0.1.0.1.4.$line-3\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Compounds in cardamom may help increase airflow to your lungs and improve breathing. When taken in powder form, cardamom may lower blood sugar.</p>', 1, 3, '2021-08-05 01:13:26', '2026-01-21 01:32:56'),
(498, 'Tejpata (Bay Leaves)', 'tejpata-bay-leaves-', '100 gm', 30, 35, 1, 14, 2, '1628111765-image-Tejpata (Bay Leaves) 100 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">The bay leaf is an aromatic leaf commonly used in cooking. It can be used whole, or as dried and ground. Bay leaves are a rich source of vitamin A, vitamin C, iron, potassium, calcium, and magnesium.</span></p>', 1, 3, '2021-08-05 01:16:05', '2026-02-01 19:33:49'),
(499, 'Radhuni Turmeric Powder (Holud)', 'radhuni-turmeric-powder-holud-', '200 gm', 140, 145, 1, 3, 5, '1628111955-image-Radhuni Turmeric Powder (Holud) 200 gm-compressed.jpg', '<p data-reactid=\".r6c195n7r8.$4056.0.1.0.1.4.$line-0\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Radhuni Turmeric Powder is a premium-quality spice, made from finely selected turmeric roots that are ground to perfection. Known for its rich color, distinctive aroma, and numerous health benefits, this turmeric powder is a must-have for enhancing the flavor and appearance of your favorite dishes.</p><p data-reactid=\".r6c195n7r8.$4056.0.1.0.1.4.$line-1\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\"></p><p data-reactid=\".r6c195n7r8.$4056.0.1.0.1.4.$line-2\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Cooking: Add to curries, lentils, and vegetables for vibrant color and flavor.</p>', 1, 3, '2021-08-05 01:19:15', '2026-02-01 18:37:58'),
(500, 'Radhuni Chilli Powder (Morich)', 'radhuni-chilli-powder-morich-', '200 gm', 135, 140, 1, 3, 5, '1628112162-image-Radhuni Chilli Powder (Morich) 200 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Radhuni powdered Chilli is vivid in color, precious in flavor. Best variety of red chilli provides more hotness. Capsaicin, the main flavoring compound for hotness and Capsanthin, the main coloring compound is blended in proper proportion to maintain the real taste of chili.</span></p>', 1, 3, '2021-08-05 01:22:42', '2026-02-01 18:49:54'),
(501, 'Shukna Morich (Dried Chillies)', 'shukna-morich-dried-chillies-', '100 gm', 45, 50, 1, 10, 2, '1628112352-image-Shukna Morich (Dried Chillies) 100 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Dried Chillies are whole chilies that have been dried to preserve their flavor and heat. These chillies come in various varieties, including red, green, and yellow, and are used to add spice, heat, and depth to a wide range of dishes.</span></p>', 1, 3, '2021-08-05 01:25:52', '2026-02-01 19:32:35'),
(502, 'Radhuni Jeera (Cumin) Powder', 'radhuni-jeera-cumin-powder-100-gm', '100 gm', 155, 160, 1, 3, 2, '1628112569-image-Radhuni Cumin (Jeera) Powder 100 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif; font-size: 16px;\">Radhuni Cumin Powder is a finely ground spice made from high-quality cumin seeds, known as jira in South Asia. It is a staple in Bangladeshi, Indian, and Middle Eastern cuisines, offering a warm, earthy flavor with a hint of citrus. perfect for households, providing a convenient and flavorful addition to your spice collection.</span></p>', 1, 3, '2021-08-05 01:29:29', '2026-01-21 01:43:38'),
(503, 'Gol Morich (Black Pepper Whole)', 'gol-morich-black-pepper-whole-', '10 gm', 15, 18, 1, 16, 2, '1628112798-image-GolMorich (Black Pepper Whole) 10 gm-compressed.jpg', '<p data-reactid=\".r6c195n7r8.$18534.0.1.0.1.4.$line-2\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Black pepper has no artificial colors or preservatives</p><p data-reactid=\".r6c195n7r8.$18534.0.1.0.1.4.$line-3\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">It has a mild spicy flavor and is used in Chinese, Vietnamese, British, and Swedish cooking. They match perfectly with eggs, cheese, lamb, fish, sausage, salad, cheese, tomatoes, strawberries, etc.</p><p data-reactid=\".r6c195n7r8.$18534.0.1.0.1.4.$line-4\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Black pepper is an exceptionally beneficial spice. It helps in digestion.</p>', 1, 3, '2021-08-05 01:33:18', '2026-02-01 19:23:56'),
(504, 'Lobongo (Cloves)', 'lobongo-cloves-', '10 gm', 20, 22, 1, 9, 2, '1628112986-image-Lobongo (Cloves) 10 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">In addition to containing several important vitamins and minerals, cloves are rich in antioxidants. Some research suggests that the compounds found in cloves might help protect against cancer. Cloves have been shown to have antimicrobial properties, meaning they can help stop the growth of microorganisms like bacteria. Studies show that the beneficial compounds in cloves could help promote liver health. The compounds found in cloves may help keep blood sugar under control. Some research indicates that the compounds found in cloves could help treat stomach ulcers.</span></p>', 1, 3, '2021-08-05 01:36:26', '2026-02-01 19:22:08'),
(505, 'Radhuni Dhoniya Powder (Coriander)', 'radhuni-dhoniya-powder-coriander-', '200 gm', 105, 110, 1, 4, 2, '1628113148-image-Radhuni Coriander Powder (Dhoniya) 200 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Providing a fragrant flavor Radhuni Powdered Coriander is high in food value. This ground coriander powder is obtained from the Coriander seed of the coriander plant. As a spice, it is used widely in many cultures and countries.</span></p>', 1, 3, '2021-08-05 01:39:08', '2026-02-01 18:30:13'),
(506, 'Radhuni Garam Masala', 'radhuni-garam-masala', '40 gm', 78, 80, 1, 2, 2, '1769934574-image-Radhuni Garam Masala Powder 40g-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif; font-size: 16px;\">A seamless blend of multiple spices mixed with cinnamon, cumin, black pepper, nutmeg, cardamom &amp; clove, and Garam Masala is the finest blend that gives a rich aroma and distinctive taste to your meals.</span></p>', 1, 3, '2021-08-05 01:41:42', '2026-02-01 19:29:34'),
(507, 'Radhuni Chilli Powder (Morich)', 'radhuni-chilli-powder-morichs-100-gm', '100 gm', 70, 75, 1, 6, 2, '1628113470-image-Radhuni Chilli Powder (Morich) 100 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Radhuni powdered Chilli is vivid in color, precious in flavor. Best variety of red chilli provides more hotness. Capsaicin, the main flavoring compound for hotness and Capsanthin, the main coloring compound is blended in proper proportion to maintain the real taste of chili.</span></p>', 1, 3, '2021-08-05 01:44:30', '2026-02-01 18:45:43');
INSERT INTO `products` (`id`, `name`, `slug`, `quantity`, `sale_price`, `actual_price`, `is_percentage`, `off`, `point`, `image`, `description`, `is_stock`, `added_by`, `created_at`, `updated_at`) VALUES
(508, 'Alu Bokhara', 'alu-bokhara', '50 gm', 40, 45, 1, 11, 2, '1628113645-image-Alu Bokhara 50 gm-compressed.jpg', '<p data-reactid=\".r6c195n7r8.$3989.0.1.0.1.4.$line-2\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Alu Bukhara, also known as plums, is a healthy food item. When dried, they are known as prunes. These sweet and juicy fruits are rich in vitamins K, C, and A, and contain antioxidants.</p><p data-reactid=\".r6c195n7r8.$3989.0.1.0.1.4.$line-3\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Some varieties of plum fruit are sour, while others are sweet. Alu Bukhara is often used as an auxiliary flavor enhancer in biryanis and other dishes. Alu Bukhara provides minerals, iron, vitamin K, and potassium. Besides culinary uses, Alu Bukhara is also used in traditional medicine for various health benefits, including aiding digestion, preventing constipation, and improving bone health.</p><p data-reactid=\".r6c195n7r8.$3989.0.1.0.1.4.$line-4\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\"></p><p data-reactid=\".r6c195n7r8.$3989.0.1.0.1.4.$line-5\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">The word Aloo is derived from the Persian word for plum, and “Bokhara” is named after the city of Bukhara in Uzbekistan. In short, Alu Bukhara means plum of Bukhara.</p>', 1, 3, '2021-08-05 01:47:25', '2026-02-01 19:20:44'),
(509, 'Radhuni Turmeric Powder (Holud)', 'radhuni-turmeric-powder-holuds-100-gm', '100 gm', 70, 75, 1, 6, 2, '1628113800-image-Radhuni Turmeric Powder (Holud) 100 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Radhuni Turmeric Powder is a vibrant and aromatic spice made from carefully selected turmeric roots. It is a staple in South Asian cooking, valued for its distinct flavor, bright yellow color, and health benefits. The powder is finely ground to ensure smooth blending in all types of dishes.</span></p>', 1, 3, '2021-08-05 01:50:00', '2026-02-01 18:36:47'),
(510, 'Kalo Jira (Black Cumin)', 'kalo-jira-black-cumin-', '100 gm', 60, 65, 1, 7, 2, '1628405161-image-Kalo Jira (Black Cumin) 100 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Black cumin is used for food ingredients. It is also used to treatment for some diseases.</span></p>', 1, 3, '2021-08-08 10:46:01', '2026-01-21 01:14:05'),
(511, 'Radhuni Roast Masala', 'radhuni-roast-masala', '35 gm', 60, 65, 1, 7, 1, '1628405310-image-Radhuni Roast Masala 35 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Radhuni easy mix roast masala gives you the optimum taste of roast in the easiest way, without having to add any other spices. just add sour curd in preparation and edible oil in cooking with chicken.</span></p>', 1, 3, '2021-08-08 10:48:30', '2026-01-19 19:06:01'),
(512, 'Radhuni Jeera (Cumin) Powder', 'radhuni-jeera-cumin-powder-200 gm', '200 gm', 300, 310, 1, 3, 5, '1628405519-image-Radhuni Jeera (Cumin) Powder 200 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Radhuni Cumin Powder is a finely ground spice made from high-quality cumin seeds, known as jira in South Asia. It is a staple in Bangladeshi, Indian, and Middle Eastern cuisines, offering a warm, earthy flavor with a hint of citrus. perfect for households, providing a convenient and flavorful addition to your spice collection.</span></p>', 1, 3, '2021-08-08 10:51:59', '2026-01-21 01:39:46'),
(513, 'Methi (Fenugreek Seed)', 'methi-fenugreek-seed-', '100 gm', 25, 30, 1, 16, 2, '1628405752-image-Methi (Fenugreek Seed) 100 gm-compressed.jpg', '<p data-reactid=\".r6c195n7r8.$3437.0.1.0.1.4.$line-0\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Fenugreek (Methi) Seeds are small, amber-colored seeds known for their distinctive, slightly bitter flavor and aromatic qualities. They are commonly used in Indian, Middle Eastern, and Mediterranean cuisines to add flavor to curries, spice blends, and pickles. Fenugreek is also celebrated for its numerous health benefits and is a key ingredient in many traditional remedies.</p><p data-reactid=\".r6c195n7r8.$3437.0.1.0.1.4.$line-1\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\"></p><p data-reactid=\".r6c195n7r8.$3437.0.1.0.1.4.$line-2\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Uses: Spice Cooking, Pickles, Sprouts, Infusions.</p>', 1, 3, '2021-08-08 10:55:52', '2026-02-01 19:18:20'),
