(515, 'Radhuni Dhoniya (Coriander) Powder', 'radhuni-dhoniya-coriander-powder', '100 gm', 58, 60, 1, 3, 2, '1628406127-image-Radhuni Dhoniya (Coriander) Powder 100 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Providing a fragrant flavor Radhuni Powdered Coriander is high in food value. This ground coriander powder is obtained from the Coriander seed of the coriander plant. As a spice, it is used widely in many cultures and countries.</span></p>', 1, 3, '2021-08-08 11:02:07', '2026-02-01 18:31:20'),
