(520, 'Dhonia (Coriander)', 'dhonia-coriander-', '100 gm', 30, 35, 1, 14, 2, '1628452825-image-Dhonia (Coriander) 100 gm-compressed.jpg', '<p data-reactid=\".ro2titl27u.$3114.0.1.0.1.4.$line-0\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Coriander Powder is a finely ground powder made from high-quality coriander seeds. It is a versatile spice widely used in South Asian cooking, known for its warm, citrusy flavor and aromatic qualities. This powder is an essential ingredient in a variety of dishes, from curries to chutneys, enhancing their taste and complexity.</p><p data-reactid=\".ro2titl27u.$3114.0.1.0.1.4.$line-1\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\"></p><p data-reactid=\".ro2titl27u.$3114.0.1.0.1.4.$line-2\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Ingredients: Pure Ground Coriander Seeds.</p><p data-reactid=\".ro2titl27u.$3114.0.1.0.1.4.$line-3\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\"></p><p data-reactid=\".ro2titl27u.$3114.0.1.0.1.4.$line-4\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Flavor Enhancer: Provides a citrusy, slightly sweet, and earthy flavor to any dish.</p><p data-reactid=\".ro2titl27u.$3114.0.1.0.1.4.$line-5\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Digestive Aid: Known for its digestive properties, it helps soothe the stomach and promotes digestion.</p><p data-reactid=\".ro2titl27u.$3114.0.1.0.1.4.$line-6\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Rich in Nutrients: Contains essential vitamins and minerals such as Vitamin C, antioxidants, and fiber.</p><p data-reactid=\".ro2titl27u.$3114.0.1.0.1.4.$line-7\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Versatile: Can be used in a wide variety of dishes, from savory to even certain sweet recipes.</p>', 1, 3, '2021-08-09 00:00:25', '2026-01-21 01:34:54'),
(521, 'Tishi (Brown Flax Seed)', 'tishi-brown-flax-seed-', '100 gm', 38, 40, 1, 5, 2, '1628453107-image-Tishi (Brown Flax Seed) 100 gm-compressed.jpg', NULL, 0, 3, '2021-08-09 00:05:07', '2026-02-01 19:08:06'),
(522, 'Radhuni Turmeric Powder (Holud)', 'radhuni-turmeric-powders-holud-500-gm', '500 gm', 195, 200, 1, 2, 5, '1628453670-image-Radhuni Turmeric Powder (Holud) 500 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Radhuni Turmeric Powder is a vibrant and aromatic spice made from carefully selected turmeric roots. It is a staple in South Asian cooking, valued for its distinct flavor, bright yellow color, and health benefits. The powder is finely ground to ensure smooth blending in all types of dishes.</span></p>', 0, 3, '2021-08-09 00:14:30', '2026-02-01 18:36:20'),
