(524, 'Tokma Seed', 'tokma-seed', '100 gm', 20, 25, 1, 20, 2, '1628454295-image-Tokma Seed 100 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Tokma Dana or Chia seeds are among the healthiest foods on the planet. They’re loaded with nutrients that can have important benefits for your body and brain. Despite their small size, chia seeds are full of important nutrients. They are an excellent source of omega-3 fatty acids, rich in antioxidants, and they provide fiber, iron, and calcium.</span></p>', 1, 3, '2021-08-09 00:24:55', '2026-02-01 19:05:54'),
(525, 'Radhuni Pach Foron', 'radhuni-pach-foron', '50 gm', 29, 30, 1, 3, 1, '1628454530-image-Radhuni Pach Foron 50 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Radhuni Panch Phoran is a traditional Bengali five-spice mix, specially crafted to add a burst of flavor and aroma to dishes. This blend of whole spices is perfect for tempering and is widely used in Bengali and South Asian cuisine.</span></p>', 1, 3, '2021-08-09 00:28:50', '2026-02-01 19:01:26'),
