(537, 'Radhuni Turmeric (Holud) Powder', 'radhuni-turmeric-holud-powder', '50 gm', 39, 40, 1, 2, 2, '1628625534-image-Radhuni Turmeric Powder 50 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Radhuni Turmeric Powder is a vibrant and aromatic spice made from carefully selected turmeric roots. It is a staple in South Asian cooking, valued for its distinct flavor, bright yellow color, and health benefits. The powder is finely ground to ensure smooth blending in all types of dishes.</span></p>', 1, 3, '2021-08-10 23:58:54', '2026-02-01 18:35:49'),
