(617, 'Greenland Ghee', 'greenland-ghee-500-gm', '500 gm', 670, 685, 0, 2, 5, '1628716726-image-Greenland Ghee 500 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">This ghee is perfect for daily cooking, adding a rich and aromatic flavor to your dishes. Use it in traditional recipes or simply drizzle over rice for an extra layer of deliciousness.</span></p>', 1, 3, '2021-08-12 01:18:46', '2026-02-01 23:13:30'),
(618, 'Greenland Ghee', 'greenland-ghee-200-gm', '200 gm', 295, 305, 0, 3, 2, '1628716839-image-Greenland Ghee 200 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">This ghee is perfect for daily cooking, adding a rich and aromatic flavor to your dishes. Use it in traditional recipes or simply drizzle over rice for an extra layer of deliciousness.</span></p>', 1, 3, '2021-08-12 01:20:39', '2026-02-01 23:13:23'),
