(623, 'Maggi Fusian Fried Rice Seasoning Mix Sachet', 'maggi-fusian-fried-rice-seasoning-mix-sachet', '6 gm', 10, 10, 1, NULL, 1, '1628750719-image-Maggi Fusian Fried Rice Seasoning Mix Sachet 6 gm-compressed.jpg', NULL, 0, 3, '2021-08-12 10:45:19', '2022-12-12 04:21:43'),
(624, 'Radhuni Biryani Masala', 'radhuni-biryani-masala', '40 gm', 55, 60, 1, 8, 2, '1628750869-image-Radhuni Biryani Masala 40 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">The Radhuni Biryani Masala is a specially crafted spice mix that simplifies the preparation of aromatic and flavorful biryani. It combines a perfect blend of authentic spices, making your biryani rich in taste and aroma while saving you time in the kitchen.</span></p>', 1, 3, '2021-08-12 10:47:49', '2026-01-21 00:47:32'),
(625, 'Radhuni Haleem Mix', 'radhuni-haleem-mix', '200 gm', 65, 70, 1, 7, 2, '1628751026-image-Radhuni Haleem Mix 200 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Radhuni Haleem Mix is will give you the authentic taste of Bangladeshi haleem which can be cooked very easily by anyone. The ingredients for cooking haleem are given inside and all you need to do is add meat and oil. Altogether, it’s a very popular item during Ramadan but can also be enjoyed with family at anytime because it\'s a healthy and tasty wholesome meal.</span></p>', 1, 3, '2021-08-12 10:50:26', '2026-01-21 00:19:56'),
(626, 'Radhuni Chatpoti Masala', 'radhuni-chatpoti-masala', '50 gm', 48, 50, 1, 4, 2, '1628751276-image-Radhuni Chatpoti Masala 50 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Radhuni Chotpoti Masala is a blend of different spices that makes the preparation easy, flavored, and tasty. Radhuni Chotpoti Masala is fresh and healthy.</span></p>', 1, 3, '2021-08-12 10:54:36', '2026-01-21 00:42:51'),
(627, 'Radhuni Chicken Masala', 'radhuni-chicken-masala', '20 gm', 15, 15, 1, NULL, 2, '1628751466-image-Radhuni Chicken Masala 20 gm-compressed.jpg', NULL, 1, 3, '2021-08-12 10:57:46', '2022-09-17 04:54:43'),
(628, 'Radhuni Beef Masala', 'radhuni-beef-masala', '25 gm', 18, 18, 1, NULL, 2, '1628751603-image-Radhuni Beef Masala 25 gm-compressed.jpg', NULL, 1, 3, '2021-08-12 11:00:03', '2022-09-17 04:54:16'),
(629, 'Radhuni Firni Mix', 'radhuni-firni-mix', '150 gm', 65, 70, 1, 7, 2, '1628751749-image-Radhuni Firni Mix 150 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Radhuni Firni Mix is made with Aromatic Rice, Almond Nut, Sodium chloride, Sugar, Cardamom, and Kewra Flavor. Radhuni Firni Mix is usually consumed as a dessert after a meal. what you only have to do is add the first mix to one liter of milk and cook for 15-20 minutes. It\'s fresh and healthy.</span></p>', 1, 3, '2021-08-12 11:02:29', '2026-01-21 00:24:07'),
(630, 'Radhuni Tehari Masala', 'radhuni-tehari-masala', '40 gm', 53, 55, 1, 3, 2, '1628751922-image-Radhuni Tehari Masala 40 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Specially made mixed spices for mutton, beef, and chicken Tehari. The mixing of different spices maintains the standard recipe to prepare delicious Tehari.</span></p>', 1, 3, '2021-08-12 11:05:22', '2026-01-21 00:49:14'),
(631, 'Knorr Krispy Fried Chicken Mix', 'knorr-krispy-fried-chicken-mix', '75 gm', 95, 100, 1, 5, 2, '1628752355-image-Knorr Krispy Fried Chicken Mix 75 gm-compressed.jpg', NULL, 0, 3, '2021-08-12 11:12:35', '2026-01-21 01:07:07'),
(632, 'Radhuni Kachchi Biryani Masala', 'radhuni-kachchi-biryani-masala', '40 gm', 65, 70, 1, 7, 2, '1628752506-image-Radhuni Kachchi Biryani Masala 40 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">The proper mixing of different spices according to the age-old recipe of biryani comes to you in radhuni biryani masala. Get the unique taste of mutton, beef, and chicken biryani at your home with ease.</span></p>', 1, 3, '2021-08-12 11:15:06', '2026-01-21 00:18:30'),
(633, 'Radhuni Borhani Masala', 'radhuni-borhani-masala', '50 gm', 38, 40, 1, 5, 2, '1628752635-image-Radhuni Borhani Masala 50 gm-compressed.jpg', NULL, 0, 3, '2021-08-12 11:17:15', '2026-01-21 01:06:25');
