(634, 'Radhuni Kala Bhuna Masala', 'radhuni-kala-bhuna-masala', '80 gm', 95, 100, 1, 5, 2, '1628752768-image-Radhuni Kala Bhuna Masala 80 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Radhuni Kala Bhuna helps you recreate the authentic traditional taste of divine Kala Bhuna which is a true legacy of the Chatgaya Taste. The flavor of a Kala Bhuna is based on a mixture of spices with the process of making it makes the recipe very easy to make at the comfort of your home.</span></p>', 1, 3, '2021-08-12 11:19:28', '2026-01-21 00:40:34'),
(635, 'Radhuni Chicken Tandoori Masala', 'radhuni-chicken-tandoori-masala', '50 gm', 75, 80, 1, 6, 2, '1628753162-image-Radhuni Chicken Tandoori Masala 50 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Radhuni Chicken Tandoori Masala is made from high quality and a selected variety of ingredients. It is natural, and free from adulterants, preservatives, artificial color, and flavor.</span></p>', 1, 3, '2021-08-12 11:26:02', '2026-01-21 00:50:24'),
(636, 'Radhuni Falooda Mix (Mango)', 'radhuni-falooda-mix-mango-', '250 gm', 80, 85, 1, 5, 2, '1663354161-image-Radhuni Falooda Mix (Mango)-compressed.jpg', NULL, 0, 3, '2021-08-12 11:29:22', '2026-01-21 01:05:20'),
