(638, 'Radhuni Kabab Masala', 'radhuni-kabab-masala', '50 gm', 95, 100, 1, 5, 2, '1628753649-image-Radhuni Kabab Masala 50 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">The Radhuni Kabab Masala is a finely blended spice mix designed to bring authentic, mouthwatering flavors to your homemade kababs. With its balanced combination of aromatic spices, it enhances the taste and texture of various kabab recipes, ensuring a professional-quality dish every time.</span></p>', 1, 3, '2021-08-12 11:34:09', '2026-01-19 18:53:36'),
