(716, 'ACI Pure Suji', 'aci-pure-suji-500-gm', '500 gm', 47, 48, 1, 2, 2, '1769949313-image-ACI Pure Suji 500gm-compressed.jpg', '<div class=\"product_description\" style=\"color: rgb(104, 113, 136); font-family: Poppins, sans-serif; font-size: 16px;\"><div class=\"pr_desc\" style=\"display: inline-block;\"><p style=\"margin-bottom: 15px; line-height: 28px;\"><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">ACI Pure Suji is made from carefully selected premium wheat using advanced milling technology resulting in best quality granular suji. It is perfect for using as a 100% natural baby food to prepare nutritious meals at home by mixing with fruits or vegetables. It is also the perfect Suji for making delicious halwa, kheer, and pitha.</span></p><div><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\"><br></span></div></div></div>', 1, 3, '2021-08-14 01:55:54', '2026-02-01 23:35:13'),
(717, 'ACI Pure Suji', 'aci-pure-suji', '250 gm', 25, 25, 1, NULL, 2, '1769949038-image-ACI Pure Suji 250 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">ACI Pure Suji is made from carefully selected premium wheat using advanced milling technology resulting in best quality granular suji. It is perfect for using as a 100% natural baby food to prepare nutritious meals at home by mixing with fruits or vegetables. It is also the perfect Suji for making delicious halwa, kheer, and pitha.</span></p>', 1, 3, '2021-08-14 01:59:20', '2026-02-01 23:30:38'),
(718, 'Teer Maida (Flour)', 'teer-maida-flour-', '1 kg', 68, 70, 1, 2, 2, '1628892729-image-Teer Maida (Flour) 1 kg-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">TEER Flour is milled from selected high-protein wheat from Canada, America, Australia and Russia using top-notch Swiss technologies from Buhler. TEER Flour is the result of attention to detail, consistency in milling, and desire to ensure the very best baking experience possible, every time. Only selected fine flour is packed for the consumers to ensure taste as well as nutrition.</span></p>', 1, 3, '2021-08-14 02:12:09', '2026-02-02 18:22:49'),
(719, 'Bashundhara Maida', 'bashundhara-maida-', '1 kg', 75, 80, 1, 6, 2, '1628892877-image-Bashundhara Maida 1 kg-compressed.jpg', NULL, 0, 3, '2021-08-14 02:14:37', '2022-11-07 06:39:28'),
(720, 'Fresh Maida', 'fresh-maida-', '1 kg', 66, 70, 1, 5, 2, '1628893088-image-Fresh Maida 1 kg-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Elevate your baking and cooking with Fresh White Flour (Maida), a versatile ingredient perfect for creating an array of delightful dishes. Packaged in a convenient 1 kg bag, this finely milled flour is ideal for making soft breads, flaky pastries, delicious naan, and a variety of Indian sweets. Our Fresh White Flour is crafted from high-quality wheat, ensuring a smooth texture and consistent performance in all your recipes. It\'s light and airy nature makes it easy to work with, allowing for perfect results every time. Whether you’re a seasoned chef or a home cook, this maida is an essential pantry staple that will enhance your culinary creations. Discover the difference with Fresh White Flour—where quality meets endless possibilities in the kitchen!</span></p>', 1, 3, '2021-08-14 02:18:08', '2026-02-02 18:36:12'),
(721, 'ACI Pure Maida', 'aci-pure-maida', '1 kg', 65, 70, 1, 7, 2, '1770016435-image-ACI Pure Maida 1 kg-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">A good Maida must have the right balance of gluten, falling number, starch, and fiber—ensured through best quality Wheat and strict quality control. Keeping these parameters and consumer needs in mind, ACI offers the best Maida for making parathas, cakes, bread, buns, or any types of snacks.</span></p>', 1, 3, '2021-08-14 02:20:38', '2026-02-02 18:16:01'),
