(723, 'Bashundhara Atta', 'bashundhara-atta-', '1 kg', 58, 60, 1, 3, 2, '1628893617-image-Bashundhara Atta 1 kg-compressed.jpg', NULL, 0, 3, '2021-08-14 02:26:57', '2022-11-07 06:37:25'),
(724, 'Fresh Atta', 'fresh-atta-', '1 kg', 55, 65, 1, 15, 2, '1628894142-image-Fresh Atta 1 kg-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Experience the goodness of Fresh Flour (Atta), a premium quality whole wheat flour that brings authentic taste and nutrition to your kitchen. Packed in a convenient 1 kg bag, this flour is perfect for making soft chapatis, fluffy parathas, and delicious baked goods. Our Fresh Flour is milled from carefully selected whole grains, ensuring maximum flavor and health benefits. Rich in dietary fiber, vitamins, and minerals, it supports a wholesome diet while adding a delightful nutty aroma to your dishes.</span></p>', 1, 3, '2021-08-14 02:35:42', '2026-02-02 18:34:15'),
(725, 'Teer Whole Wheat Atta', 'teer-whole-wheat-atta', '1 kg', 68, 70, 1, 2, 2, '1628894278-image-Teer Whole Wheat Atta 1 kg-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">All the nutrients of Bran, Endosperm, and Wheat Germ stay intact and protected, TEER Whole Wheat Atta Provides the wholesome goodness of fine, fiber-rich, vitamin-and-mineral-loaded atta for healthier foods. TEER is the first brand to introduce Whole Wheat Atta in Bangladesh. This top-selling whole wheat atta is pantry all-star, rich in flavor, and healthy to boot.</span></p>', 1, 3, '2021-08-14 02:37:58', '2026-02-02 18:30:56'),
(726, 'ACI Pure Atta', 'aci-pure-atta', '1 kg', 55, 65, 1, 15, 2, '1770016065-image-ACI Pure Atta 1 kg-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">ACI Pure Atta is prepared with strict quality control to ensure the best results every time. Using European state-of-the-art technology, it retains the right balance of gluten, minerals, starch, and natural nutrients. Roti made from ACI Pure Atta is always soft and tasty—perfect for everyday consumption.</span></p>', 1, 3, '2021-08-14 02:40:46', '2026-02-02 18:07:45'),
(727, 'ACI Pure Brown Atta', 'aci-pure-brown-atta', '1 kg', 65, 70, 1, 7, 2, '1770016825-image-ACI Pure Brown Atta 1 kg-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">ACI Nutrilife Brown Atta has the nutrition of whole wheat which provides more fibre and mineral. ACI Nutrilife Brown Atta controls the level of glucose in blood making it ideal for diabetic patients. It also prevents obesity and heart disease, and the anti-oxidant in the product helps in anti-aging.</span></p>', 1, 3, '2021-08-14 02:43:29', '2026-02-02 18:20:25'),
