(737, 'Ispahani Mirzapore Tea Bag', 'ispahani-mirzapore-tea-bag-', '50 pcs', 95, 100, 1, 5, 2, '1628926358-image-Ispahani Mirzapore Tea Bag 50 pcs-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Tea leaves are a natural source of goodness. Ispahani Mirzapore Tea is very special blend made from tea leaves of the garden of Bangladesh. Ispahani Mirzapore Tea Bag is a blend of cheer and refresher.</span></p>', 1, 3, '2021-08-14 11:32:38', '2026-02-15 18:44:56'),
(738, 'Ispahani Mirzapore Tea Bag', 'ispahani-mirzapore-tea-bag', '25 pcs', 48, 50, 1, 4, 2, '1628926518-image-Ispahani Mirzapore Tea Bag 25 pcs-compressed.jpg', NULL, 0, 3, '2021-08-14 11:35:18', '2026-01-03 18:17:47'),
(739, 'Kazi & Kazi Green Tea', 'kazi-kazi-green-tea-40-pcs-p', '40 pcs', 205, 215, 1, 4, 3, '1628927362-image-Kazi & Kazi Green Tea 60 gm 40 pcs-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Grown organically, Kazi &amp; Kazi Green tea is blessed by Mother Nature with a flavor, very earthy and light, which will refresh you and make your aura bright. This allegorical fountain of youth is rich in antioxidants that help in weight reduction and cancer prevention.</span></p>', 1, 3, '2021-08-14 11:49:22', '2026-02-07 17:54:50'),
