(770, 'Tora Bika Cappuccino 25 gm', 'tora-bika-cappuccino-25-gm', '1 pcs', 55, 55, 1, NULL, 2, '1629013120-image-Tora Bika Cappuccino 25 gm1 pcs-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Having Tora Bika Cappuccino ia a Great way to Start a nice Day! It\'s taste and flavor will make your mind fresh to start a successful day.</span></p>', 1, 3, '2021-08-15 11:38:40', '2026-02-07 19:26:53'),
(771, 'Nestle Nescafe 3 in 1 Coffee 14 gm', 'nestle-nescafe-3-in-1-coffee-14-gm', '1 pcs', 15, 15, 1, NULL, 1, '1770451053-image-Nestle Nescafe 3 in 1 Coffee Mix-compressed.jpg', '<p data-reactid=\".3zd7j47zsk.$3839.0.1.0.1.4.$line-2\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">A balanced &amp; delicious mix of coffee, sugar, and creamer that you will feel from the first sip till the last drop!</p><p data-reactid=\".3zd7j47zsk.$3839.0.1.0.1.4.$line-3\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Small in size so that you can take it with you anywhere and enjoy a nice cup of coffee.</p><p data-reactid=\".3zd7j47zsk.$3839.0.1.0.1.4.$line-4\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Pour coffee mixes from 14g sachet in 120ml hot (80°C) water. Stir up well to get a perfect cup of NESCAFÉ</p><p data-reactid=\".3zd7j47zsk.$3839.0.1.0.1.4.$line-5\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Variant: NESCAFÉ 3in1</p>', 1, 3, '2021-08-15 11:41:04', '2026-02-07 18:57:33'),
(772, 'Nestle Nescafe Classic Instant Coffee Jar', 'nestle-nescafe-classic-instant-coffees-jar-45-gm', '45 gm', 270, 275, 0, 1, 2, '1770449383-image-Nestle Nescafe Classic Instant Coffee Jar 45 gm-compressed.jpg', '<p data-reactid=\".3zd7j47zsk.$16680.0.1.0.1.4.$line-2\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Start your day right with the first sip of NESCAFÉ Classic</p><p data-reactid=\".3zd7j47zsk.$16680.0.1.0.1.4.$line-3\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">NESCAFÉ Classic soluble coffee is perfect for any time of the day</p><p data-reactid=\".3zd7j47zsk.$16680.0.1.0.1.4.$line-4\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Add a teaspoon (1.5g) of NESCAFÉ Classic and 5g Nestlé Coffeemate into 120ml hot (80°C) water. Add sugar as per your taste and stir up well to get a perfect cup of NESCAFÉ</p><p data-reactid=\".3zd7j47zsk.$16680.0.1.0.1.4.$line-5\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Storage Instruction: Close the lid tightly after use, always use a dry spoon, and store it in a cool, dry, and hygienic place.</p><p data-reactid=\".3zd7j47zsk.$16680.0.1.0.1.4.$line-6\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Variant: NESCAFÉ CLASSIC</p><p data-reactid=\".3zd7j47zsk.$16680.0.1.0.1.4.$line-7\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Net Weight: 45 gm</p><p data-reactid=\".3zd7j47zsk.$16680.0.1.0.1.4.$line-8\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Marketed by Nestle Bangladesh Limited.</p>', 1, 3, '2021-08-15 11:45:51', '2026-02-07 18:29:43'),
