(888, 'Spa Drinking Water 2.25 ltr', 'spa-drinking-water-2-25-ltr', '6 pcs', 200, 240, 1, 16, 5, '1629359924-image-Spa Drinking Water 2-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Spa Drinking Water offers pure, refreshing hydration with its 2-liter bottle. Sourced from high-quality filtration processes, Spa ensures clean, crisp water that’s ideal for staying hydrated throughout the day, whether at work, the gym, or during outdoor activities.</span></p>', 1, 3, '2021-08-19 11:58:44', '2026-02-11 18:09:54'),
(889, 'Tang Orange', 'tang-orange-75-gms', '75 gm', 95, 100, 1, 5, 2, '1770797207-image-Tang Orange 75 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Beat the heat with the refreshing Orange Tang. Enjoy its yummy taste with the benefits of Vitamin A, B &amp; C and Iron. Rejuvenate your day by drinking a glass full of fresh and energetic drink- which gives you 60% of your Vitamin C requirement of the day. Tang makes water more fun to drink ensuring that your family stays hydrated – a glass of Tang gives your child vitamins required for the entire day. No need to add sugar, just add the powder to water and enjoy the delicious drink on the go.- Instantly refreshes you - Filled with the goodness of orange and enriched with vitamin a, b, c and iron. - No allergens included - Easy to Prepare - Best had after sports or anytime you need recharging.</span></p>', 1, 3, '2021-08-19 12:10:06', '2026-02-11 19:06:47'),
(890, 'Glaxose-D Energy Drink BIB', 'glaxose-d-energy-drink-bib', '200 gm', 95, 99, 1, 4, 2, '1770799640-image-Glucomax D 200 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">GlucoMax D is a non-flavoured energy drink that can be used by children and adults alike. It helps in maintaining an active lifestyle for sports person, active business person or are a busy housewife. It is the energy drink made from glucose, which is the simplest form of sugar, and serves as an instant source of energy. The drink is also infused with minerals such as Calcium, Phosphorus &amp; Vitamin D GlucoMax D is an easily digestible glucose drink which is a fast and effective provider of energy.</span></p>', 1, 3, '2021-08-19 12:20:30', '2026-02-11 19:47:20'),
(891, 'Horlicks Health And Nutrition Drink Jar', 'horlicks-health-and-nutrition-drink-jar-1-kg', '1 kg', 840, 850, 0, 1, 5, '1767857689-image-Horlicks Health And Nutrition Drink Jar 1 kg-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Filled with a wide range of vitamins and minerals including Calcium, Iron, Zinc, Phosphorous, and Vitamins A, C, E, D, B1, B2, B6, and B12 - Horlicks is a nourishing beverage that helps support your child’s growth. Produced from a mix of malted barley, wheat, and milk, this unrivaled tasty recipe has been providing nutrition to people for many years. Horlicks help to make kids Taller, Stronger, and Sharper!</span></p>', 1, 3, '2021-08-19 12:32:17', '2026-01-08 18:34:49'),
