(932, 'Godrej Aer Room Air Freshener Spray Cool Surf Blue', 'godrej-aer-room-air-freshener-spray-cool-surf-blue', '300 ml', 280, 300, 1, 6, 5, '1770882850-image-Godrej Aer Cool Room Spray-compressed.jpg', '<p data-reactid=\".1pbwzlvcx9q.$11033.0.1.0.1.4.$line-2\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Breezy and how. My fragrance is inspired by the smooth sea breeze flowing over coral reefs in Mauritius. It just can’t get breezier than this. Here’s Godrej Aer spray. And here’s what we would like you to know about it. We thought, what’s the harm in pleasing two of your senses for the price of one? You’d agree it doesn’t look like any ordinary air freshener and once you get a whiff of the fragrance, you’ll agree it doesn’t smell ordinary either. Easy to use, long-lasting, and available in six designer fragrances.</p><p data-reactid=\".1pbwzlvcx9q.$11033.0.1.0.1.4.$line-3\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\"></p><p data-reactid=\".1pbwzlvcx9q.$11033.0.1.0.1.4.$line-4\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">About the brand: We are here to change the air, the way it spells, and the way it smells. Introducing Godrej Aer, a range of home and car fragrances. You would have noticed how we spell \"Aer\", a tad bit differently. That\'s the little difference we intend to make to your life, your car, and your home. No, we won\'t change your future, your world, or your boss. All we can do is to make your car, home and you feel nice. Now quickly add Aer to your dictionary, take a deep breath, and smile.</p>', 0, 3, '2021-08-21 11:53:21', '2026-02-12 18:55:02'),
(933, 'Spring Air Freshener Lemon Fresh', 'spring-air-freshener-lemon-fresh-', '300 ml', 215, 225, 1, 4, 5, '1629532525-image-Spring Air Freshener Lemon Fresh 300 ml-compressed.jpg', NULL, 0, 3, '2021-08-21 11:55:25', '2026-02-12 19:17:02'),
(934, 'Angelic Fresh Air Freshener Orchid Breeze', 'angelic-fresh-air-freshener-orchid-breeze-', '300 ml', 320, 340, 1, 5, 5, '1770878751-image-Angelic Fresh Air Freshener Orchid Breeze-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Angelic Fresh Air Freshener Orchid Breeze has cool soothing fragrance and to make the environment relaxed and tranquil. Its enticing fragrances are made from essential oils extracted from fruits, flowers and plants which lift your mood up and take you to the world of imagination.</span></p>', 1, 3, '2021-08-21 11:57:25', '2026-02-12 17:45:51'),
(935, 'Fay Air Freshener Lavender 3 in 1', 'fay-air-freshener-lavender-3-in-1', '300 ml', 320, 340, 1, 5, 5, '1770882136-image-Fay Air Freshener Lavender-compressed.jpg', '<p data-reactid=\".1pbwzlvcx9q.$2589.0.1.0.1.4.$line-2\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Fay Lavender leaves the room with the unique fragrance of the beautiful blue-violet flower of Lavender shrubs. The rich extracts from the essential oil of the Lavender make the air elegantly perfumed.</p><p data-reactid=\".1pbwzlvcx9q.$2589.0.1.0.1.4.$line-3\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\"></p><p data-reactid=\".1pbwzlvcx9q.$2589.0.1.0.1.4.$line-4\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Fay Air Freshener Lavender 3 in 1 provides long-lasting freshness with a soothing lavender scent. It not only eliminates odors but also disinfects and refreshes the air. Perfect for creating a clean, pleasant atmosphere in your home or office.</p>', 1, 3, '2021-08-21 11:59:49', '2026-02-12 18:42:16'),
