(973, 'Vim Dishwashing Liquid Refill', 'vim-dishwashing-liquid-refill', '200 ml', 50, 50, 1, NULL, 2, '1771964958-image-Vim Dishwashing Liquid Pouch-compressed.jpg', '<p data-reactid=\".sihgod7lro.$4476.0.1.0.1.4.$line-0\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Vim liquid, with double lemon power, cleans 2x number of dishes vs. bars and gives you complete cleaning without leaving any residue, unlike Dishwash Bars. It is also great value for money with one spoon of Vim liquid being enough to clean a full sink of dirty utensils. Its superior fragrance leaves your utensils smelling fresh, while its pH-neutral formula is gentle on your hands.</p><p data-reactid=\".sihgod7lro.$4476.0.1.0.1.4.$line-1\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">It also keeps your expensive utensils like non-stick cookware looking new for longer as it cleans without scratching the surface and is recommended for non-stick cookware.</p><p data-reactid=\".sihgod7lro.$4476.0.1.0.1.4.$line-2\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\"></p><p data-reactid=\".sihgod7lro.$4476.0.1.0.1.4.$line-3\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">For cooking vessels, add a drop of Vim liquid directly on the scrubber and wash to get rid of tough stains. For other utensils, tiffins, and dishes, take a spoonful of Vim, mix it in a bowl of water use the mixture to wash.</p>', 1, 3, '2021-08-22 11:13:01', '2026-02-25 07:29:18'),
(974, 'Vim Diswashing Liquid', 'vim-diswashing-liquid-1-ltr', '950 ml', 230, 240, 1, 4, 5, '1771965264-image-Vim Dishwashing Liquid 950 ml-compressed.jpg', '<p data-reactid=\".sihgod7lro.$16433.0.1.0.1.4.$line-0\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Vim liquid, with double lemon power. It cleans 2x number of dishes vs. bars and gives you complete cleaning without leaving any residue, unlike Dishwash Bars. It is also great value for money with one spoon of Vim liquid being enough to clean a full sink of dirty utensils. Its superior fragrance leaves your utensils smelling fresh, while its pH-neutral formula is gentle on your hands.</p><p data-reactid=\".sihgod7lro.$16433.0.1.0.1.4.$line-1\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">It also keeps your expensive utensils like non-stick cookware looking new for longer as it cleans without scratching the surface and is recommended for non-stick cookware.</p><p data-reactid=\".sihgod7lro.$16433.0.1.0.1.4.$line-2\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\"></p><p data-reactid=\".sihgod7lro.$16433.0.1.0.1.4.$line-3\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">For cooking vessels, add a drop of Vim liquid directly on the scrubber and wash to get rid of tough stains. For other utensils, tiffins, and dishes, take a spoonful of Vim, mix it in a bowl of water use the mixture to wash.</p>', 1, 3, '2021-08-22 11:17:34', '2026-02-25 07:34:24'),
(975, 'Vim Dishwashing Powder', 'vim-dishwashing-powder-500-gm', '500 gm', 50, 50, 1, NULL, 2, '1629616796-image-Vim Dishwashing Powder 500 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">VIm Scouring Powder is an all-purpose cleaner that is ideal for removing tough stains on sinks, floor tiles, kitchen utensils, and bathrooms. It comes with an improved formula which facilitates a convenient washing experience to the consumer. Not advised to use plastic utensils.</span></p>', 1, 3, '2021-08-22 11:19:56', '2026-02-25 07:31:05'),
(976, 'Vim Dishwashing Liquid', 'vim-dishwashing-liquid', '475 ml', 125, 130, 1, 3, 2, '1771964810-image-Vim Dishwashing Liquid 475 ml-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Vim liquid, with the power of 100 lemons, gives you complete cleaning without leaving any residue, unlike Dishwash Bars. It is also great value for money with one spoon of Vim liquid being enough to clean a full sink of dirty utensils. Its superior fragrance leaves your utensils smelling fresh, while its pH neutral formula is gentle on your hands It also keeps your expensive utensils like non-stick cookware looking new for longer as it cleans without scratching the surface and is recommended for non-stick cookware. For cooking vessels, add a drop of Vim liquid directly on the scrubber and wash to get rid of tough stains. For other utensils, tiffins and dishes, take a spoonful of Vim, mix it in a bowl of water use the mixture to wash. So go ahead and enjoy the Vim liquid experience.</span></p>', 1, 3, '2021-08-22 11:22:07', '2026-02-25 07:26:50'),
(977, 'Trix Dishwashing Liquid Lemon Bottle', 'trix-dishwashing-liquid-lemon-bottle-500-ml', '500 ml', 145, 150, 1, 3, 3, '1771964634-image-Trix Dishwashing Liquid Lemon Bottle-compressed.jpg', '<p data-reactid=\".sihgod7lro.$7635.0.1.0.1.4.$line-1\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Dishwashing Liquid: Makes dishwashing as easy and effortless as it can be</p><p data-reactid=\".sihgod7lro.$7635.0.1.0.1.4.$line-2\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Removes grease stains and unseen food residue from the dishes.</p><p data-reactid=\".sihgod7lro.$7635.0.1.0.1.4.$line-3\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Available Variant: Lemon; Available Sizes: 5 Litre Refill pack, 500 ml bottle &amp; 250ml Refill Pack.</p><p data-reactid=\".sihgod7lro.$7635.0.1.0.1.4.$line-4\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\"></p><p data-reactid=\".sihgod7lro.$7635.0.1.0.1.4.$line-5\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Trix dishwashing liquid’s power-rich thick foam quickly removes grease stains and unseen food residue from the dishes bringing your dishes scratch-free &amp; sparkling clean.</p><p data-reactid=\".sihgod7lro.$7635.0.1.0.1.4.$line-6\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Usage Information: To clean a few dishes, pour 1 teaspoon of Trix dishwashing liquid into one cup of water. Then soak a sponge in the water and wash the dishes. To clean several dishes, pour 3 teaspoons of Trix dishwashing liquid on 5 Ltr. of water. Dip the dishes in the water for 5 minutes. Use a sponge or soft cloth to wipe them clean.</p>', 1, 3, '2021-08-22 11:26:49', '2026-02-25 07:23:54'),
