(1327, 'Ponds Vanishing Cream', 'ponds-vanishing-cream-28-gm', '28 gm', 70, 75, 1, 6, 2, '1773817971-image-Pond\'s Vanishing Cream 28gm-compressed.jpg', '<p><span style=\"color: rgb(46, 49, 56); white-space-collapse: preserve;\"><font face=\"Arial\">Ponds Vanishing Cream designed for oily skin. Get soft and supple skin all through the summer. This matte formula ensures oil free smooth skin.</font></span></p>', 1, 3, '2021-09-21 00:35:15', '2026-03-18 17:12:51'),
(1328, 'Pond\'s Bright Beauty Cream (Imported)', 'pond-s-bright-beauty-cream-imported-50-gm', '50 gm', 400, 475, 1, 15, 5, '1773818643-image-Pond\'s Bright Beauty Cream (Imported) 50gm-compressed.jpg', '<p><span style=\"color: rgb(73, 69, 79); font-family: Montserrat;\">Make your skin look its best with Pond\'s White Beauty Fairness Cream. This cream is designed to provide you multifaceted benefits. It not only makes your skin look lighter but also reduces dark spots. You can make your skin look radiant and bright with the regular use of this cream that is has SPF 15 to protect the skin against the harmful effects of UV rays. Now, you can nourish and protect your skin at the same time. This cream is suitable for daily use as it is effective yet gentle. Get your dream skin in a convenient way with the help of Pond\'s White Beauty Fairness Cream.</span></p>', 1, 3, '2021-09-21 00:43:56', '2026-03-18 17:24:03'),
(1329, 'Pond\'s Face Wash Daily', 'pond-s-face-wash-daily-100-gm', '100 gm', 145, 150, 1, 3, 5, '1773642066-image-Pond\'s Face Wash Daily 100 ml-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">New Pond\'s Daily Face Wash is designed to give your skin a fresh feel every day. This face wash is designed for all skin types. Active cleansing system cleanses thoroughly &amp; gently. Cares for your skin as it cleans more gently than a soap can. Menthol &amp; Peppermint fusion helps to leave your skin fresh and renewed. This Ultra-mild face wash is perfect for everyday exfoliation. Get fresh skin every day with the new Pond\'s Daily Face Wash.</span></p>', 1, 3, '2021-09-21 00:48:43', '2026-03-16 16:21:06'),
(1330, 'Dove Face Wash Beauty Moisture', 'dove-face-wash-beauty-moisture', '50 ml', 160, 165, 1, 3, 5, '1632171193-image-Dove Face Wash Beauty Moisture 50 ml-compressed.jpg', NULL, 0, 3, '2021-09-21 00:53:13', '2026-01-05 16:47:45'),
(1331, 'Glow & Lovely Ayurvedic Care Face Cream', 'glow-lovely-ayurvedic-care-face-cream', '50 gm', 190, 195, 1, 2, 2, '1773647012-image-Glow & Lovely Face Cream Ayurvedic Care 50g-compressed.jpg', '<p><font face=\"Arial\"><font color=\"#2e3138\"><span style=\"white-space-collapse: preserve;\">Glow &amp; Lovely</span></font><span style=\"color: rgb(46, 49, 56); white-space-collapse: preserve;\"> ayurvedic care gives an unbeatable natural glow, instantly. Infused with 16 ayurvedic expert ingredients. Clears marks and improves complexion. Calms and soothes skin. Reduces uneven skin tone. Not just a cream, Ayurvedic glow expert</span></font></p>', 1, 3, '2021-09-21 00:57:52', '2026-03-16 17:43:32'),
(1332, 'Ponds Face Wash White Beauty', 'ponds-face-wash-white-beauty-50-gm', '50 gm', 115, 120, 1, 4, 3, '1773472199-image-Pond\'s Face Wash Bright Beauty 50 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Is your true complexion lost or hidden? Over time dead skin cells accumulate on your skin, hiding your true complexion, making you look dull and dark. New and improved Pond’s White Beauty Face Wash. 1st ever facewash with Double Brightening Action to renew your complexion every day. Now get the clinically proven benefits with Pond’s. Your complexion is hidden under layers of dead skin cells and pollution. Pond’s White Beauty Face Wash with advanced vitamin B3+ formula will cleanse your skin and gives you spotless glow. It goes deep to clean dead skin cells and uncovers millions of new cells- so that you can get your hidden complexion back. Infused with vitamin B3+, it removes layers of dead skin cells and it strengthens skin’s natural renewal process, revealing new bright cells. Renew your complexion with everyday wash. Clinically proven to give you glow from the first wash. Its double brightness action wipes out dead skin cells so that you can say goodbye to skin dullness. This helps bring out the complexion locked inside which shows clearly after every use of Pond’s White Beauty Facewash. This is truly your solution to a spot less and glowing skin. Dead skin removal Spot less glow Fades dark spots Advanced B3+ formula Clinically proven facewash With Advanced Vitamin B3</span></p>', 1, 3, '2021-09-21 01:02:57', '2026-03-14 17:09:59'),
(1333, 'Pond\'s Face Wash Daily', 'pond-s-face-wash-daily', '50 gm', 80, 85, 1, 5, 1, '1773642175-image-Pond\'s Face Wash Daily 50gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">New Pond\'s Daily Face Wash is designed to give your skin a fresh feel every day. This face wash is designed for all skin types. Active cleansing system cleanses thoroughly &amp; gently. Cares for your skin as it cleans more gently than a soap can. Menthol &amp; Peppermint fusion helps to leave your skin fresh and renewed. This Ultra-mild face wash is perfect for everyday exfoliation. Get fresh skin every day with the new Pond\'s Daily Face Wash.</span></p>', 1, 3, '2021-09-21 01:05:52', '2026-03-16 16:22:55'),
