(1336, 'Glow & Lovely Ayurvedic Care Face Cream', 'glow-lovely-ayurvedic-care-face-cream-25-gm', '25 gm', 100, 105, 1, 4, 5, '1773814046-image-Glow & Lovely Ayurvedic Care Face Cream 25 gm-compressed.jpg', '<p><span style=\"color: rgb(46, 49, 56); white-space-collapse: preserve;\"><font face=\"Arial\">Glow &amp; Lovely Ayurvedic Care Cream provides natural glow, hydration, improve uneven skin tone, reduce the number, size and intensity of dark spots and allows entire formulas to penetrate deep into the dermis. The power of natural plant antioxidants, this cream calms and soothes skin, speeds up regeneration processes from within, restoring your skin layer by layer and making wrinkles less visible.</font></span></p>', 1, 3, '2021-09-21 01:18:46', '2026-03-18 16:07:26'),
