(1354, 'Meril Milk Soap Bar', 'meril-milk-soap-bar-100-gm', '100 gm', 58, 60, 1, 3, 1, '1773904734-image-Meril Milk Soap Bar 100gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Who doesn’t wish for fresh soft, velvety skin? To your rescue from skin roughness and protect against it, switch to Meril Milk Soap Bar. You are special and your skin needs the very best. Blending the ancient imperial luxury of milk baths with its 6 times more moisturizing power, Meril Milk Soap Bar will give you fresh and smooth skin. So, indulge in the world of moisture with the Meril Milk Soap Bar. Ingredients: Sodium soap, Aqua, Glycerine,Titanium Dioxide, EDTA, Perfume, Pure Milk.</span></p>', 1, 3, '2021-09-22 00:02:17', '2026-03-19 17:18:54'),
(1355, 'Meril Vitamin C Soap Bar (Lemon & Lime)', 'meril-vitamin-c-soap-bar-lemon-lime-100-gm', '100 gm', 58, 60, 1, 3, 1, '1773905655-image-Meril Vitamin C Soap Bar (Lemon & Lime) 100gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Meril Vitamin C Soap Bar is enriched with Vitamin C to brighten your skin and even out your complexion. It helps reduce dark spots and supports a natural, healthy glow. Infused with lemon and lime, it provides a refreshing scent while gently cleansing your skin. Regular use boosts radiance, leaving your skin feeling fresh, clean, and vibrant.</span></p>', 1, 3, '2021-09-22 00:05:31', '2026-03-19 17:34:15'),
(1356, 'Meril Milk & Beli Soap Bar', 'meril-milk-beli-soap-bar-100-gm', '100 gm', 58, 60, 1, 3, 1, '1773905002-image-Meril Milk & Beli Soap Bar 100gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Meril Milk &amp; Beli Soap Bar 100 gm is a gentle soap enriched with the goodness of milk and beli extracts. It nourishes and moisturizes the skin, leaving it soft, smooth, and refreshed. The 100 gm bar is perfect for daily use, offering a refreshing cleanse with a natural touch.</span></p>', 1, 3, '2021-09-22 00:07:26', '2026-03-19 17:23:22'),
