(2799, 'Kodomo Baby Oil', 'kodomo-baby-oil-100-ml', '100 ml', 550, 613, 1, 10, 10, '1768372115-image-Kodomo Baby oil 100 ml-compressed.jpg', '<p style=\"margin: 22px 0px; letter-spacing: 0.03em; color: rgb(21, 22, 23); font-family: db_adman_x; font-size: 26px;\"><span style=\"font-size: 22px;\">“Happy and Comfy Moment\" with Kodomo Baby Oil which are specifically developed for the newborn baby with delicate and lovely scent.&nbsp;</span></p><p style=\"margin: 22px 0px; letter-spacing: 0.03em; color: rgb(21, 22, 23); font-family: db_adman_x; font-size: 26px;\">Kodomo Baby Oil contain various&nbsp;ingredients which are beneficial for the baby as follow:-</p><ul style=\"margin-right: 0px; margin-bottom: 15px; margin-left: 0px; padding: 0px 0px 0px 40px; list-style-position: initial; list-style-image: initial; color: rgb(21, 22, 23); font-family: db_adman_x; font-size: 26px;\"><li style=\"float: none; list-style-type: disc;\">Natural Tsubaki Oil - Help to moisturize&nbsp;and nourish the baby skin<br>&nbsp;</li><li style=\"float: none; list-style-type: disc;\">Vitamin E -&nbsp;Strengthen the baby’s skin barrier<br>&nbsp;</li><li style=\"float: none; list-style-type: disc;\">Non-greasy feel &amp; Fast-absorbing formula -&nbsp;For enjoyable and happy&nbsp;moments as the oil is not sticky and easy to absorb</li></ul><p style=\"margin: 22px 0px; letter-spacing: 0.03em; color: rgb(21, 22, 23); font-family: db_adman_x; font-size: 26px;\">Kodomo Baby Oil is dermatologically tested and free from Parabens, Phthalates, Gluten, Silicones, Preservative and Dyes. The Kodomo Baby Oil is also being tested clinically that it is enable to moisture the baby skin for 24 hours.</p><div><br></div>', 1, 3, '2026-01-14 17:28:35', '2026-01-14 17:28:35'),
(2800, 'Kodomo Baby Shampoo', 'kodomo-baby-shampoo', '100 ml', 300, 320, 1, 6, 10, '1768373038-image-Kodomo Baby Shampoo 100 ml-compressed.jpg', '<p style=\"margin: 22px 0px; letter-spacing: 0.03em; color: rgb(21, 22, 23); font-size: 26px;\"><font face=\"Times New Roman\">“Fragrance and gentle shampoo for delicate hair and scalp\"&nbsp;<br>The hair and scalps of the newborns are delicate and need gentle care. KODOMO has got you covered with KODOMO shampoo for kids: Original scent for newborn (from 0 year and above)</font></p><ul style=\"margin-right: 0px; margin-bottom: 15px; margin-left: 0px; padding: 0px 0px 0px 40px; list-style-position: initial; list-style-image: initial; color: rgb(21, 22, 23); font-size: 26px;\"><li style=\"float: none; list-style-type: disc;\"><font face=\"Times New Roman\">pH Balanced Cleansing : maintain the balance while gently cleaning the hair and scalp</font></li><li style=\"float: none; list-style-type: disc;\"><font face=\"Times New Roman\">Carefully selected scents approved by international Fragrance Association</font></li><li style=\"float: none; list-style-type: disc;\"><font face=\"Times New Roman\">Free of SLS, Parabens, Silicone, Mineral Oils, and Alcohols.</font></li><li style=\"float: none; list-style-type: disc;\"><font face=\"Times New Roman\">Dematologically tested hypoallergenic to sensitive skins.</font></li><li style=\"float: none; list-style-type: disc;\"><font face=\"Times New Roman\">Awarded \"Mommy\'s Choice &amp; Editor\'s Choice\" for Best shampoo category in Amarin Baby &amp; Kids Award 2022</font></li></ul><p style=\"margin: 22px 0px; letter-spacing: 0.03em; color: rgb(21, 22, 23); font-size: 26px;\"><font face=\"Times New Roman\">Suitable for adults with sensitive and irritable scalps as well.</font></p>', 1, 3, '2026-01-14 17:43:58', '2026-01-14 17:43:58'),
