(2819, 'Radhuni Bbq Masala', 'radhuni-bbq-masala', '50 gm', 75, 80, 1, 6, 2, '1768809587-image-Radhuni Bbq Masala-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">With its tantalizing blend of rich spices and flavors, Radhuni BBQ Masala helps you recreate the traditional barbeque experience at home.</span></p>', 1, 3, '2026-01-19 18:59:47', '2026-01-19 18:59:47'),
(2820, 'Radhuni Chicken Masala', 'radhuni-chicken-masala-100-gm', '100 gm', 90, 95, 1, 5, 2, '1768914995-image-Radhuni Chicken Masala 100 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Radhuni Chicken Masala is a premium spice blend crafted to give your chicken dishes an authentic, rich, and flavorful taste. This masala is perfect for making a variety of chicken preparations, from curries to dry dishes. The perfect combination of spices adds depth and aroma to your meals, making them a delightful experience for your taste buds.</span></p>', 1, 3, '2026-01-21 00:16:35', '2026-01-21 00:16:35'),
(2821, 'Radhuni Duck Curry Masala', 'radhuni-duck-curry-masala', '33 gm', 55, 60, 1, 8, 2, '1768916278-image-Radhuni Duck Curry Masala-compressed.jpg', '<p data-reactid=\".ro2titl27u.$57044.0.1.0.1.4.$line-0\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Duck Curry is more than just a dish in Bangladesh; it is a celebration of winter warmth, festive gatherings, and regional pride. Radhuni Duck Curry Masala is crafted with a splendid blend of spices that perfectly balance the rich, tender flavors of duck meat.</p><p data-reactid=\".ro2titl27u.$57044.0.1.0.1.4.$line-1\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\"></p><p data-reactid=\".ro2titl27u.$57044.0.1.0.1.4.$line-2\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Inspired by the authentic recipes of rural kitchens and the vibrant food culture of Bangladesh, Radhuni Duck Curry Masala brings the essence of Bangladeshi heritage straight to your table in a convenient way.</p>', 1, 3, '2026-01-21 00:37:58', '2026-01-21 00:37:58'),
(2822, 'Radhuni Chaat Masala', 'radhuni-chaat-masala', '50 gm', 70, 75, 1, 6, 2, '1768917445-image-Radhuni chat Masala-compressed.jpg', '<p><span style=\"font-family: Roboto, -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, Helvetica, sans-serif; white-space-collapse: break-spaces;\">Radhuni Chaat Masala is more than just a seasoning; it’s a gateway to the rich culinary heritage of Indian subcontinental cuisines like Chana Chaat, Fruit Chaat, Doi Bora, Doi Fuska, Dosa etc. Its unique blend of spices brings life to a variety of dishes, allowing home cooks to create authentic flavors with ease. Whether you’re a seasoned chef or a beginner in the kitchen, incorporating Radhuni Chaat Masala into your cooking can elevate your meals and introduce your palate to new, exciting tastes.</span></p>', 1, 3, '2026-01-21 00:57:25', '2026-01-21 00:57:25'),
