(2825, 'Aji No Moto Testing salt', 'aji-no-moto-testing-salt-40-gm', '40 gm', 20, 20, 1, NULL, 2, '1770278772-image-Aji No Moto Testing salt 40 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Enhance the flavors in your dishes with AJI-NO-MOTO, a trusted monosodium glutamate seasoning. Known for it\'s umami taste, it brings out the best in savory recipes, making your meals more flavorful and satisfying. Ideal for soups, stir-fries, and sauces.</span></p>', 1, 3, '2026-02-05 19:06:12', '2026-02-05 19:06:12'),
(2826, 'Aji No Moto Testing salt', 'aji-no-moto-testing-salt-18-gm', '18 gm', 10, 10, 1, NULL, 1, '1770278857-image-Aji No Moto Testing salt 18 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Enhance the flavors in your dishes with AJI-NO-MOTO, a trusted monosodium glutamate seasoning. Known for it\'s umami taste, it brings out the best in savory recipes, making your meals more flavorful and satisfying. Ideal for soups, stir-fries, and sauces.</span></p>', 1, 3, '2026-02-05 19:07:37', '2026-02-05 19:07:37'),
(2827, 'Kazi & Kazi Green Tea', 'kazi-kazi-green-tea', '20 pcs', 110, 115, 1, 4, 2, '1770447219-image-Kazi & Kazi Green Tea 30g-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Grown organically, Kazi &amp; Kazi Green tea is blessed by Mother Nature with a flavor, very earthy and light, which will refresh you and make your aura bright. This allegorical fountain of youth is rich in antioxidants that help in weight reduction and cancer prevention.</span></p>', 1, 3, '2026-02-07 17:53:39', '2026-02-07 17:53:39'),
(2828, 'Nestle Nescafe Classic Instant Coffee Jar', 'nestle-nescafe-classic-instant-coffee-jar', '24 gm', 195, 195, 0, NULL, 2, '1770449582-image-Nestle Nescafe Classic Instant Coffee Jar 24 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Experience the allure of a rich and aromatic cup of coffee with Nestlé Nescafé Classic Instant Coffee. Encased in a 24 gm jar, this coffee blend has stood the test of time, offering a seamless way to enjoy a classic cup of coffee anytime, anywhere. Nescafé Classic Instant Coffee is known for its captivating aroma that fills the air as soon as you open the jar. The rich fragrance is a precursor to the delightful taste that follows. Indulge in the balanced and full-bodied flavor that has made Nescafé a beloved coffee choice for decades. Each sip is a testament to the careful blending and roasting techniques that have perfected its taste. Experience the convenience of instant coffee without compromising on taste. With Nescafé Classic, all it takes is a spoonful, hot water, and a stir to create a cup that satisfies your coffee cravings.</span></p>', 1, 3, '2026-02-07 18:33:02', '2026-02-07 18:33:02'),
(2829, 'Nestle Nescafe Creamy Latte Coffee', 'nestle-nescafe-creamy-latte-coffee-18-gm', '18 gm', 20, 20, 0, NULL, 1, '1770450028-image-Nescafe Creamy Latte 18g-compressed.jpg', '<p data-reactid=\".3zd7j47zsk.$23777.0.1.0.1.4.$line-0\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">NESCAFÉ CREAMY LATTE has just the right touch of smoothness to elevate your coffee experience</p><p data-reactid=\".3zd7j47zsk.$23777.0.1.0.1.4.$line-1\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">The perfect blend of creaminess in your coffee makes every sip enjoyable.</p><p data-reactid=\".3zd7j47zsk.$23777.0.1.0.1.4.$line-2\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Every sip provides you with comforting warmth and revives your spirit for the day.</p><p data-reactid=\".3zd7j47zsk.$23777.0.1.0.1.4.$line-3\" style=\"-webkit-tap-highlight-color: transparent; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Pour coffee mixes from 18g sachet into 120ml hot (80°C) water. Stir up well to get a perfect cup of creamy coffee</p>', 1, 3, '2026-02-07 18:40:28', '2026-02-07 18:40:28'),
(2830, 'Nescafe Classic Coffee Mini Pack', 'nescafe-classic-coffee-mini-pack', '1 pcs', 5, 5, 0, NULL, 1, '1770451378-image-Nescafe Classic Coffee Mini Pack-compressed.jpg', NULL, 1, 3, '2026-02-07 19:02:58', '2026-02-07 19:02:58'),
(2831, 'Nestea Lemon Iced Tea', 'nestea-lemon-iced-tea-18-gm', '18 gm', 20, 20, 0, NULL, 1, '1770451764-image-Nestea-compressed.jpg', '<p><span style=\"color: rgb(46, 49, 56); font-family: &quot;Open Sans&quot;; white-space-collapse: preserve;\">Nestea Iced Tea Lemon has Vitamin C, which supports the body\'s immune system. And which can meet 60 percent of your daily requirement. Enjoy its great refreshingly good taste. Each glass of Nestea iced tea meets 60 percent of your daily requirement for vitamin C. Vitamin C supports the body\'s immune system.</span></p>', 1, 3, '2026-02-07 19:09:24', '2026-02-07 19:09:24'),
(2832, 'Nestea Iced Tea Lemon', 'nestea-iced-tea-lemon-500-gm', '500 gm', 430, 460, 0, 6, 10, '1770452037-image-Nestea Iced Tea Lemon 500 gm-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Nestea Iced Tea Lemon has Vitamin C, which supports the body\'s immune system. And which can meet 60 percent of your daily requirement.</span></p>', 1, 3, '2026-02-07 19:13:57', '2026-02-07 19:13:57'),
(2833, 'Seylon Instant Milk Tea 3 in 1', 'seylon-instant-milk-tea-3-in-1', '15 gm', 10, 10, 1, NULL, 1, '1770452329-image-Seylon Instant Milk Tea 3 in 1-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Indulge in the convenience and deliciousness of SEYLON Instant Milk Tea, a perfect blend of premium ingredients that makes milk tea preparation quick and effortless.</span></p>', 1, 3, '2026-02-07 19:18:49', '2026-02-07 19:18:49'),
(2834, 'Kofi House 3 in 1 Coffee 14 gm', 'kofi-house-3-in-1-coffee-14-gm', '1 pcs', 10, 10, 1, NULL, 1, '1770452669-image-Kofi House 14gm 3 in 1 Coffee-compressed.jpg', '<p><span style=\"color: rgb(2, 21, 35); font-family: aktiv-grotesk, sans-serif; font-size: 13px; letter-spacing: -0.03px;\">Enjoy a rich and convenient coffee experience with Kofi House 3in1 Instant Coffee.&nbsp;</span><span class=\"citation-15 citation-end-15\" style=\"color: rgb(2, 21, 35); font-family: aktiv-grotesk, sans-serif; font-size: 13px; letter-spacing: -0.03px;\">Each 14g sachet is a perfect blend of high-quality coffee, non-dairy creamer, and just the right amount of sugar, creating a smooth and balanced cup every time.</span></p>', 1, 3, '2026-02-07 19:24:29', '2026-02-07 19:24:29'),
(2835, 'Pran Drinko Mango Juice', 'pran-drinko-mango-juice', '250 ml', 29, 30, 1, 3, 1, '1770538690-image-Pran Drinko Mango Juice 250 ml-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Indulge in the tropical taste of Pran Drinko Mango Juice. Crafted from ripe mangoes, this juice offers a rich, smooth, and sweet flavor that\'s perfect for any occasion.</span></p>', 1, 3, '2026-02-08 19:18:10', '2026-02-08 19:18:10'),
(2836, 'Farm Fresh Chocolate Flavoured Uht Milk', 'farm-fresh-chocolate-flavoured-uht-milk-', '250 ml', 39, 40, 1, 2, 1, '1770539128-image-Farm Fresh Chocolate Flavoured Uht Milk 250ml-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Farm Fresh Chocolate Flavoured UHT Milk combines the goodness of full-cream milk with rich chocolate flavor. This 250 ml UHT pack provides a creamy, satisfying drink perfect for chocolate lovers. Enjoy it chilled or at room temperature anytime of the day.</span></p>', 1, 3, '2026-02-08 19:25:28', '2026-02-08 19:25:28'),
(2837, 'Aarong Dairy Lassi', 'aarong-dairy-lassi', '200 ml', 39, 40, 1, 2, 1, '1770539442-image-Aarong Dairy Lassi-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Aarong Dairy’s milk-based beverages are tasty and nutritious. It adds a whole lot of goodness to every occasion. Share and Enjoy!</span></p>', 1, 3, '2026-02-08 19:30:42', '2026-02-08 19:30:42'),
(2838, 'Mojo', 'mojo-2-ltr', '2 ltr', 105, 110, 1, 4, 1, '1770623374-image-Mojo 2 ltr-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Mojo is the no. 1 local cola brand in Bangladesh. The name “MOJO” is derived from the word “Moja” which means fun. Has a taste that refreshes, for a rewardingly uplifting experience.</span></p>', 1, 3, '2026-02-09 18:49:34', '2026-02-09 18:49:34'),
(2839, 'Mojo Zero Can', 'mojo-zero-can-', '250 ml', 50, 50, 1, NULL, 1, '1770624101-image-Mojo Zero Can 250ml-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">Mojo Zero offers a refreshing, sugar-free alternative to regular soft drinks. The 250 ml can is perfect for those looking to enjoy a fizzy drink without the extra calories. Mojo Zero keeps you energized and refreshed with its bold, unique flavor.</span></p>', 1, 3, '2026-02-09 19:01:41', '2026-02-09 19:01:41'),
(2840, 'Speed Ginger Can', 'speed-ginger-can', '250 ml', 60, 60, 1, NULL, 1, '1770625152-image-Speed Ginger Can 250 ml-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">likely a refreshing and energizing beverage that combines the crisp and taste of Ginger with a carbonated base. It could be a popular choice for those who enjoy the invigorating taste of Ginger in a convenient and portable 250 ml can size.</span></p>', 1, 3, '2026-02-09 19:19:12', '2026-02-09 19:19:12');
