(2842, 'Clemon', 'clemon-500-ml', '500 ml', 39, 40, 1, 2, 1, '1770707721-image-Clemon 500 ml-compressed.jpg', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Segoe UI&quot;, Helvetica, &quot;Droid Sans&quot;, Arial, &quot;lucida grande&quot;, tahoma, verdana, arial, sans-serif;\">It is a good lemon-flavored drink. Having it makes you refreshed—Must-have as your companion for parties, traveling, and any time of the day.</span></p>', 1, 3, '2026-02-10 18:15:21', '2026-02-10 18:15:21'),
